+    ...(config.options?.search ?? {}),
+    ...(options ?? {}),
+  };
+  const model = readNonEmptyString(mergedOptions.model);
+  const instructions = readNonEmptyString(mergedOptions.instructions);
+
+  return {
+    ...(model ? { model } : {}),
+    ...(instructions ? { instructions } : {}),
+  };
+}
+
